import React, { useState } from 'react';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import { Grid } from '@mui/material';
import TopBar from './components/TopBar';
import UserList from './components/UserList';
import UserDetail from './components/UserDetail';
import UserPhotos from './components/UserPhotos';
import LoginRegister from './components/LoginRegister';

const App = () => {
  const [topBarContext, setTopBarContext] = useState('Vui lòng chọn một người dùng');
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);

  const handleLoginSuccess = (user) => {
    setIsLoggedIn(true);
    setCurrentUser(user);
    setTopBarContext(`Xin chào, ${user.login_name}`);
  };

  return (
    <Router>
      <div className="app-container">
        <TopBar context={topBarContext} />
        <div className="cs142-main-topbar-buffer" />

        <Grid container spacing={2}>
          <Grid item sm={3}>
            <UserList />
          </Grid>
          <Grid item sm={9}>
            <Routes>
              <Route
                path="/login"
                element={<LoginRegister onLoginSuccess={handleLoginSuccess} />}
              />
              <Route
                path="/users/:userId"
                element={<UserDetail setContext={setTopBarContext} />}
              />
              <Route
                path="/photos/:userId"
                element={<UserPhotos setContext={setTopBarContext} />}
              />
              <Route
                path="/"
                element={
                  isLoggedIn ? (
                    <div className="typography">Welcome! Click on a user.</div>
                  ) : (
                    <LoginRegister onLoginSuccess={handleLoginSuccess} />
                  )
                }
              />
            </Routes>
          </Grid>
        </Grid>
      </div>
    </Router>
  );
};

export default App;
